import{_ as a,o as e,c as o,a2 as r}from"./chunks/framework.e-meDy3u.js";const d=JSON.parse('{"title":"Q1 · 入职第一周，只能做一个 AI 工具，选什么？","description":"","frontmatter":{},"headers":[],"relativePath":"q1.md","filePath":"q1.md"}'),n={name:"q1.md"};function s(p,t,i,q,l,h){return e(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="q1-·-入职第一周-只能做一个-ai-工具-选什么" tabindex="-1">Q1 · 入职第一周，只能做一个 AI 工具，选什么？ <a class="header-anchor" href="#q1-·-入职第一周-只能做一个-ai-工具-选什么" aria-label="Permalink to &quot;Q1 · 入职第一周，只能做一个 AI 工具，选什么？&quot;">​</a></h1><p class="hqq-lede">「只能做一个」是一道减法题。结论的依据只有一条：这个东西离钱有多近。</p><h2 id="结论" tabindex="-1">结论 <a class="header-anchor" href="#结论" aria-label="Permalink to &quot;结论&quot;">​</a></h2><p>做一个「爆款素材资产库」，起手先服务自有私店。</p><p>这不是一个新东西，是把已经赢过的素材从散在各个人手里、各个群里，变成按卖点、人群、场景随取随用的结构化弹药库。两个进料口：已赢素材归库（把赢过的沉淀下来）、技术面那个原型工作流持续生成新候选（探索新的）。</p><p><strong>起手先服务自有私店，不上来就碰代理。</strong> 哪条素材该追投、该二创，库直接给答案。等私店跑出成绩，这张成绩单才是后面放大给代理的说服力。</p><hr><h2 id="为什么选这个" tabindex="-1">为什么选这个 <a class="header-anchor" href="#为什么选这个" aria-label="Permalink to &quot;为什么选这个&quot;">​</a></h2><p><strong>给正在赢的公司，&quot;实验复盘&quot;这个词会踩雷。</strong> 对正在赢的公司，&quot;你们为什么爆不清楚&quot;这个隐含信息会让人觉得是在贬低现有成绩。库的定位不一样：是&quot;让赢法更好用&quot;，不是&quot;找出你们过去为什么输&quot;。</p><p><strong>痛点 1（素材乱）和痛点 3（代理各自为战）是同一条断链的两截。</strong> 先修素材在自有私店的资产化，跑通了，代理放大是自然延伸，不是另起炉灶。</p><p><strong>这个定位命中三个实际价值点：</strong> 降本增效（省找素材、传素材的重复人力）、标准化（代理从各自为战变成统一军火供给）、杠杆（一次整理，整个代理网受益）。</p><p><strong>关于&quot;这算不算 Agent&quot;：诚实比装酷值钱。</strong> 第一周这东西 80% 是脚本 + 表格 + 结构化 LLM 调用，20% 才沾 Agent。明确说明&quot;先把地基打好，让未来真正的 Agent 有干净数据可吃&quot;——这种诚实表达比强装 Agent 项目更扎实，也更站得住脚。</p><hr><h2 id="诚实边界" tabindex="-1">诚实边界 <a class="header-anchor" href="#诚实边界" aria-label="Permalink to &quot;诚实边界&quot;">​</a></h2><p>代理是挂昊七七链接分销还是各自开店卖，尚待入职第一周核实。不影响第一周（第一周只碰自有私店），只影响第三步放大时怎么铺。两手都准备了，入职第一周就会确认。</p><p>私店的可投放体量是真正的承重假设。如果私店体量很小、大部分 GMV 在代理，起跑点换成 1-2 个最配合的代理，方法论不变。</p>',16)])])}const c=a(n,[["render",s]]);export{d as __pageData,c as default};
